837	
838	    function fmtDate(str) {
839	      const d = new Date(str + 'T00:00:00');
840	      return d.toLocaleDateString('de-DE', { day: 'numeric', month: 'long', year: 'numeric' });
841	    }
842	    function fmtShort(str) {
843	      const d = new Date(str + 'T00:00:00');
844	      return d.toLocaleDateString('de-DE', { day: 'numeric', month: 'short' });
845	    }
846	
847	    async function searchAvailability() {
