2	/**
3	 * cms/api/translate-all.php
4	 * POST: Re-translates every cms_content row from DE → EN using the
5	 *       currently configured TranslationService (DeepL / LibreTranslate).
6	 *
7	 * Only ADMIN users may trigger this. Silent fail per-row so a single bad
8	 * field never aborts the whole batch.
9	 *
10	 * Response: { success, total, translated, errors, last_error? }
11	 */
12	declare(strict_types=1);
13	define('BASE_PATH', dirname(__DIR__));
14	require_once BASE_PATH . '/config/bootstrap.php';
15	require_once BASE_PATH . '/includes/cms-content.php';
16	
17	// Long-running task — bump timeout
18	@set_time_limit(600);
19	@ini_set('memory_limit', '256M');
20	
21	cmsEnsureSchema();
22	
23	$user = requireAdmin(jsonMode: true);
24	
25	// CSRF: accept header OR body token
26	$body  = json_decode(file_get_contents('php://input') ?: '{}', true) ?? [];
27	$token = $_SERVER['HTTP_X_CSRF_TOKEN'] ?? $body['csrf_token'] ?? '';
28	if (!empty($_SESSION['csrf_token']) && !hash_equals($_SESSION['csrf_token'], $token)) {
29	    if (empty($_SESSION['user_id'])) {
30	        jsonError('Nicht authentifiziert.', 401);
31	    }
32	}
33	
34	use Maxiworx\CMS\SettingsRepository;
35	use Maxiworx\Translation\TranslationService;
36	
37	$db       = getDbConnection();
38	$settings = new SettingsRepository($db);
39	
40	$apiKey = trim((string)$settings->get('translation_api_key', ''));
41	if ($apiKey === '') {
42	    jsonError('Kein Translation-API-Key konfiguriert.', 422);
43	}
44	
45	try {
46	    $translator = new TranslationService($db, $settings);
47	} catch (\Throwable $e) {
48	    jsonError('TranslationService nicht verfügbar: ' . $e->getMessage(), 500);
49	}
50	
51	// Pull rows where EN may be (re)translated. Two cases qualify:
52	//   1. en_manual = 0 (auto-eligible, normal case)
53	//   2. STALE: TRIM(value_en) = TRIM(value_de)  — EN is a literal copy of DE,
54	//      which can never be a real manual translation. Older saves with broken
55	//      DeepL leave these in the DB, sometimes incorrectly flagged en_manual=1.
56	//      We override the flag for these.
57	//
58	// Rows that are en_manual = 1 AND have a different EN text are PRESERVED.
59	try {
60	    $rows = $db->query(
61	        "SELECT id, value_de FROM cms_content
62	         WHERE TRIM(value_de) <> ''
63	           AND (en_manual = 0 OR TRIM(value_en) = TRIM(value_de))"
64	    )->fetchAll(\PDO::FETCH_ASSOC);
65	} catch (\Throwable $e) {
66	    // Older schema without en_manual column → fall back to all rows
67	    $rows = $db->query(
68	        "SELECT id, value_de FROM cms_content WHERE TRIM(value_de) <> ''"
69	    )->fetchAll(\PDO::FETCH_ASSOC);
70	}
71	
72	// Count how many rows are genuinely manual (different EN text) and were skipped
73	$preserved = 0;
74	try {
75	    $preserved = (int)$db->query(
76	        "SELECT COUNT(*) FROM cms_content
77	         WHERE TRIM(value_de) <> ''
78	           AND en_manual = 1
79	           AND TRIM(value_en) <> TRIM(value_de)"
80	    )->fetchColumn();
81	} catch (\Throwable $e) { /* swallow */ }
82	
83	$total      = count($rows);
84	$translated = 0;
85	$errors     = 0;
86	$lastError  = null;
87	
88	// Try the update with en_manual reset; fall back if column missing
89	$updateWithFlag = null;
90	$updatePlain    = $db->prepare(
91	    'UPDATE cms_content SET value_en = ?, updated_by = ? WHERE id = ?'
92	);
93	try {
94	    $updateWithFlag = $db->prepare(
95	        'UPDATE cms_content SET value_en = ?, updated_by = ?, en_manual = 0 WHERE id = ?'
96	    );
97	} catch (\Throwable $e) { /* older schema */ }
98	
99	foreach ($rows as $row) {
100	    try {
101	        $en = $translator->translate((string)$row['value_de'], 'de', 'en');
102	        if (trim($en) === '') {
103	            $errors++;
104	            continue;
105	        }
106	        if ($updateWithFlag !== null) {
107	            $updateWithFlag->execute([$en, (int)$user['id'], (int)$row['id']]);
108	        } else {
109	            $updatePlain->execute([$en, (int)$user['id'], (int)$row['id']]);
110	        }
111	        $translated++;
112	    } catch (\Throwable $e) {
113	        $errors++;
114	        $lastError = $e->getMessage();
115	    }
116	}
117	
118	jsonResponse([
119	    'success'    => true,
120	    'total'      => $total,
121	    'translated' => $translated,
122	    'preserved'  => $preserved,
123	    'errors'     => $errors,
124	    'last_error' => $lastError,
125	]);
