22	             . $e->getMessage() . ' in ' . $e->getFile() . ':' . $e->getLine() . PHP_EOL;
23	    $logDir  = __DIR__ . '/../logs';
24	    if (!is_dir($logDir)) @mkdir($logDir, 0750, true);
25	    @file_put_contents($logDir . '/frontend-errors.log', $msg, FILE_APPEND | LOCK_EX);
26	    if ((getenv('APP_ENV') ?: 'production') === 'development') {
27	        echo "\n<!-- CMS-ERROR [{$context}]: " . htmlspecialchars($e->getMessage()) . " -->\n";
28	    }
29	}
