151	// ── Idempotent schema auto-migration ──────────────────────────────────────────
152	/**
153	 * Runs the MigrationRunner exactly once per request. Forwarders that need
154	 * the schema to be current (admin pages, API endpoints that may touch new
155	 * columns) call this defensively at the top of the request. The runner
156	 * itself is idempotent — already-applied migrations are skipped.
157	 *
158	 * Silent fail: a schema error never breaks user-facing pages. Errors land
159	 * in cms/logs/frontend-errors.log via cmsLogError().
160	 */
161	function cmsEnsureSchema(): void
162	{
163	    static $done = false;
164	    if ($done) return;
165	    $done = true;
166	    if (!function_exists('getDbConnection')) return;
167	
168	    try {
169	        $db = getDbConnection();
170	
171	        // The PSR-4 autoloader is only registered when bootstrap.php has been
172	        // loaded (admin/API context). Frontend pages load this file directly
173	        // without bootstrap, so include the runner manually if not yet loaded.
174	        if (!class_exists(\Maxiworx\CMS\MigrationRunner::class)) {
175	            $rfile = dirname(__DIR__)
176	                   . DIRECTORY_SEPARATOR . 'src'
177	                   . DIRECTORY_SEPARATOR . 'CMS'
178	                   . DIRECTORY_SEPARATOR . 'MigrationRunner.php';
179	            if (file_exists($rfile)) {
180	                require_once $rfile;
181	            } else {
182	                return; // can't run schema; not fatal for content reads
183	            }
184	        }
185	
186	        $runner = new \Maxiworx\CMS\MigrationRunner(
187	            $db,
188	            dirname(__DIR__) . DIRECTORY_SEPARATOR . 'migrations'
189	        );
190	        $result = $runner->migrate();
191	        if (!empty($result['errors'])) {
192	            foreach ($result['errors'] as $err) {
193	                cmsLogError(
194	                    'cmsEnsureSchema:' . $err['file'],
195	                    new \RuntimeException($err['error'])
196	                );
197	            }
198	        }
199	    } catch (\Throwable $e) {
200	        cmsLogError('cmsEnsureSchema', $e);
201	    }
202	}
