204	// ── Language detection ────────────────────────────────────────────────────────
205	function cmsLang(): string
206	{
207	    // URL parameter: ?lang=en
208	    if (isset($_GET['lang']) && in_array($_GET['lang'], ['de','en'], true)) {
209	        if (session_status() === PHP_SESSION_NONE) session_start();
210	        $_SESSION['fe_lang'] = $_GET['lang'];
211	    }
212	    if (session_status() === PHP_SESSION_NONE) session_start();
213	    return $_SESSION['fe_lang'] ?? 'de';
214	}
