216	// ── Load all content fields for a page ───────────────────────────────────────
217	/**
218	 * @return array<string, array{de: string, en: string}>
219	 */
220	function cmsContent(string $pageSlug): array
221	{
222	    static $cache = [];
223	    if (isset($cache[$pageSlug])) {
224	        return $cache[$pageSlug];
225	    }
226	    if (!function_exists('getDbConnection')) {
227	        cmsLogError('cmsContent', new \RuntimeException('getDbConnection nicht verfügbar — DB-Config fehlt.'));
228	        return $cache[$pageSlug] = [];
229	    }
230	    try {
231	        $db   = getDbConnection();
232	        $stmt = $db->prepare(
233	            'SELECT field_key, value_de, value_en FROM cms_content WHERE page_slug = ?'
234	        );
235	        $stmt->execute([$pageSlug]);
236	        $result = [];
237	        foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $row) {
238	            $result[$row['field_key']] = ['de' => $row['value_de'], 'en' => $row['value_en']];
239	        }
240	        $cache[$pageSlug] = $result;
241	        return $result;
242	    } catch (\Throwable $e) {
243	        cmsLogError('cmsContent:' . $pageSlug, $e);
244	        return $cache[$pageSlug] = [];
245	    }
246	}
