250	 * Returns the field value in the current (or specified) language.
251	 * Falls back to DE if EN is empty.
252	 */
253	function c(array $content, string $key, ?string $lang = null): string
254	{
255	    $lang ??= cmsLang();
256	    $row = $content[$key] ?? null;
257	    if ($row === null) return '';
258	    $val = $row[$lang] ?? '';
259	    if ($val === '' && $lang !== 'de') {
260	        $val = $row['de'] ?? '';
261	    }
262	    return htmlspecialchars($val, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8');
263	}
