278	// ── Feature flag helper ───────────────────────────────────────────────────────
279	function cmsFlag(string $key, bool $default = false): bool
280	{
281	    static $flags = null;
282	    if ($flags === null) {
283	        if (!function_exists('getDbConnection')) { return $default; }
284	        try {
285	            $db   = getDbConnection();
286	            // Read ALL settings (not just type='bool'), so flags saved via API also work.
287	            // A value of '1' is treated as true, anything else as false.
288	            $stmt = $db->query("SELECT setting_key, value FROM cms_settings");
289	            $flags = [];
