301	// ── Media slot helper ─────────────────────────────────────────────────────────
302	function cmsMedia(string $pageSlug, string $slotKey): string
303	{
304	    static $slots = [];
305	    $cacheKey = $pageSlug . ':' . $slotKey;
306	    if (isset($slots[$cacheKey])) return $slots[$cacheKey];
307	    if (!function_exists('getDbConnection')) { return $slots[$cacheKey] = ''; }
308	    try {
309	        $db   = getDbConnection();
310	        $stmt = $db->prepare(
311	            'SELECT m.storage_path FROM cms_media_slots s
312	             JOIN cms_media m ON m.id = s.media_id
313	             WHERE s.page_slug = ? AND s.slot_key = ? LIMIT 1'
314	        );
315	        $stmt->execute([$pageSlug, $slotKey]);
316	        $path = $stmt->fetchColumn();
317	        // Use BASE_WEB_PATH constant (set by bootstrap) or fall back to env / default
318	        $base = defined('BASE_WEB_PATH') ? BASE_WEB_PATH : rtrim((string)(getenv('APP_BASE_PATH') ?: '/maxiworx'), '/');
319	        $slots[$cacheKey] = $path ? $base . '/cms/uploads/' . $path : '';
320	    } catch (\Throwable $e) {
321	        cmsLogError('cmsMedia:' . $slotKey, $e);
322	        $slots[$cacheKey] = '';
323	    }
324	    return $slots[$cacheKey];
325	}
