353	/**
354	 * Returns the $limit most recent published blog posts including body_html.
355	 * Returns an empty array if the table does not yet exist.
356	 *
357	 * @return array<int, array{id:int, title:string, slug:string, topic:string,
358	 *                           excerpt:string, body_html:string, cover_path:string,
359	 *                           published_at:string|null, created_at:string}>
360	 */
361	function cmsBlogPosts(int $limit = 3): array
362	{
363	    if (!function_exists('getDbConnection')) return [];
364	    try {
365	        $db = getDbConnection();
366	        // Auto-publish any scheduled posts whose time has arrived
367	        try {
368	            $db->exec(
369	                "UPDATE blog_posts
370	                 SET status = 'published', published_at = NOW(), scheduled_at = NULL
371	                 WHERE status = 'draft'
372	                   AND scheduled_at IS NOT NULL
373	                   AND scheduled_at <= NOW()"
374	            );
375	        } catch (\Throwable $e) { /* scheduled_at column may not exist on older installs */ }
376	
377	        // Try with EN columns; fall back without if migration 011 not applied.
378	        try {
379	            $stmt = $db->prepare(
380	                'SELECT id, title, title_en, slug, topic, topic_en,
381	                        excerpt, excerpt_en, body_html, body_html_en, cover_path,
382	                        published_at, created_at
383	                 FROM blog_posts
384	                 WHERE status = \'published\'
385	                 ORDER BY published_at DESC, created_at DESC
386	                 LIMIT ?'
387	            );
388	        } catch (\Throwable $e) {
389	            $stmt = $db->prepare(
390	                'SELECT id, title, slug, topic, excerpt, body_html, cover_path,
391	                        published_at, created_at
392	                 FROM blog_posts
393	                 WHERE status = \'published\'
394	                 ORDER BY published_at DESC, created_at DESC
395	                 LIMIT ?'
396	            );
397	        }
398	        $stmt->bindValue(1, $limit, \PDO::PARAM_INT);
399	        $stmt->execute();
400	        $rows = $stmt->fetchAll(\PDO::FETCH_ASSOC);
401	
402	        // Normalise: every row should have an *_en field, even if empty
403	        foreach ($rows as &$row) {
404	            $row['title_en']      = (string)($row['title_en']      ?? '');
405	            $row['topic_en']      = (string)($row['topic_en']      ?? '');
406	            $row['excerpt_en']    = (string)($row['excerpt_en']    ?? '');
407	            $row['body_html_en']  = (string)($row['body_html_en']  ?? '');
408	        }
409	        unset($row);
410	        return $rows;
411	    } catch (\Throwable $e) {
412	        // Table may not exist yet — silently return empty
413	        return [];
414	    }
415	}
