434	/**
435	 * Returns all active ACP instances for a given page, sorted by sort_order.
436	 * Returns an empty array if the feature is disabled or the table doesn't exist.
437	 *
438	 * Usage in frontend PHP:
439	 *   if (cmsFlag('acp_enabled')) {
440	 *       $acpInstances = cmsAcpInstances('equipment');
441	 *       foreach ($acpInstances as $acp) {
442	 *           // $acp['title'], $acp['label_a'], $acp['label_b']
443	 *           // $acp['track_a_url'], $acp['track_b_url']  ← absolute web URLs
444	 *       }
445	 *   }
446	 *
447	 * @return array<int, array{id:int, title:string, label_a:string, label_b:string,
448	 *                           track_a_path:string, track_b_path:string,
449	 *                           track_a_url:string, track_b_url:string,
450	 *                           sort_order:int}>
451	 */
452	function cmsAcpInstances(string $pageSlug = 'equipment'): array
453	{
454	    if (!function_exists('getDbConnection')) return [];
455	    try {
456	        $db = getDbConnection();
457	
458	        // Auto-create table on first call so the frontend never breaks
459	        $db->exec("
460	            CREATE TABLE IF NOT EXISTS acp_instances (
461	                id           INT UNSIGNED   AUTO_INCREMENT PRIMARY KEY,
462	                page_slug    VARCHAR(100)   NOT NULL DEFAULT 'equipment',
463	                title        VARCHAR(200)   NOT NULL DEFAULT '',
464	                label_a      VARCHAR(100)   NOT NULL DEFAULT 'Track A',
465	                label_b      VARCHAR(100)   NOT NULL DEFAULT 'Track B',
466	                track_a_path VARCHAR(500)   NOT NULL DEFAULT '',
467	                track_b_path VARCHAR(500)   NOT NULL DEFAULT '',
468	                status       ENUM('active','inactive') NOT NULL DEFAULT 'active',
469	                sort_order   SMALLINT UNSIGNED NOT NULL DEFAULT 0,
470	                created_by   INT UNSIGNED   NOT NULL DEFAULT 1,
471	                created_at   DATETIME       NOT NULL DEFAULT CURRENT_TIMESTAMP,
472	                updated_at   DATETIME       NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
473	                INDEX idx_page_status_order (page_slug, status, sort_order)
474	            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
475	        ");
476	
477	        $stmt = $db->prepare(
478	            "SELECT id, title, label_a, label_b, track_a_path, track_b_path, sort_order
479	             FROM acp_instances
480	             WHERE page_slug = ? AND status = 'active'
481	             ORDER BY sort_order ASC, id ASC"
482	        );
483	        $stmt->execute([$pageSlug]);
484	        $rows = $stmt->fetchAll(\PDO::FETCH_ASSOC);
485	
486	        $base = defined('BASE_WEB_PATH') ? BASE_WEB_PATH : rtrim((string)(getenv('APP_BASE_PATH') ?: '/maxiworx'), '/');
487	        foreach ($rows as &$row) {
488	            $row['track_a_url'] = $row['track_a_path'] ? $base . '/cms/uploads/' . $row['track_a_path'] : '';
489	            $row['track_b_url'] = $row['track_b_path'] ? $base . '/cms/uploads/' . $row['track_b_path'] : '';
490	        }
491	        unset($row);
492	        return $rows;
493	    } catch (\Throwable $e) {
494	        cmsLogError('cmsAcpInstances', $e);
495	        return [];
496	    }
497	}
