500	/**
501	 * Renders price block or alternative based on price_status field.
502	 * @param array  $content   page content array
503	 * @param string $prefix    e.g. 'recording' → looks for recording.price, recording.unit etc.
504	 * @return string  HTML
505	 */
506	function cmsPriceBlock(array $content, string $prefix, string $lang = 'de'): string
507	{
508	    $row    = $content[$prefix . '.price_status'] ?? null;
509	    $status = $row[$lang] ?? $row['de'] ?? 'visible';
510	
511	    if ($status === 'hidden') {
512	        return '';
513	    }
514	    if ($status === 'on_request') {
515	        return '<div class="price-on-request">Preis auf Anfrage</div>';
516	    }
517	
518	    $price = htmlspecialchars(cRaw($content, $prefix . '.price', $lang));
519	    $unit  = htmlspecialchars(cRaw($content, $prefix . '.unit', $lang));
520	    $note  = htmlspecialchars(cRaw($content, $prefix . '.note', $lang));
521	
522	    return '<div class="service-card__price">
523	        <div class="price-amount">' . $price . '</div>
524	        <div class="price-unit">' . $unit . '</div>
525	        ' . ($note ? '<div class="price-note">' . $note . '</div>' : '') . '
526	    </div>';
527	}
