200	  /* ---- Helpers ---- */
201	  function getPageSlug() {
202	    // Match  /maxiworx/<slug>.php  →  <slug>
203	    const m = window.location.pathname.match(/\/([a-z0-9_\-]+)\.php(?:$|[?#])/i);
