209	  function loadPageContent(slug) {
210	    if (contentCache[slug]) return Promise.resolve(contentCache[slug]);
211	    return fetch(CONTENT_API + '?page=' + encodeURIComponent(slug), {
212	      method:      'GET',
213	      credentials: 'same-origin',
214	      cache:       'no-store'
215	    })
216	      .then(function (r) { return r.json(); })
217	      .then(function (j) {
218	        if (j && j.success && j.data) {
219	          contentCache[slug] = j.data;
