233	   *           → "+ 3 weitere Künstler anzeigen" / "+ Show 3 more artists"
234	   */
235	  function cmsT(key, args) {
236	    const t   = uiTranslations[currentLang] || uiTranslations.de;
237	    let   out = t[key];
238	    if (out === undefined) return key;            // fail open: show the key
239	    if (args && typeof args === 'object') {
240	      Object.keys(args).forEach(function (k) {
241	        out = out.replace(new RegExp('\\{' + k + '\\}', 'g'), String(args[k]));
242	      });
243	    }
244	    return out;
