254	      let   val = t[key];
255	      if (val === undefined) return;
256	      // Optional placeholder substitution via data-i18n-args='{"count":3}'
257	      const argsAttr = el.getAttribute('data-i18n-args');
258	      if (argsAttr) {
259	        try {
260	          const args = JSON.parse(argsAttr);
261	          Object.keys(args).forEach(function (k) {
262	            val = val.replace(new RegExp('\\{' + k + '\\}', 'g'), String(args[k]));
263	          });
