/**
 * Maxiworx — i18n.js  (Live language switch, no page reload)
 *
 * Behaviour:
 *  1. UI-chrome strings (nav, footer, hero-scroll) → translated from the
 *     uiTranslations dictionary below.
 *  2. CMS-driven elements (carry data-cms-key) → text comes from the database
 *     via /maxiworx/cms/api/public-content.php  → fetched once per page slug,
 *     cached in memory, swapped via element.textContent on language change.
 *  3. Slide captions live in data-caption-de / data-caption-en attributes —
 *     PHP writes both, JS picks the right one.
 *  4. Hidden URL placeholders <span data-cms-key="*.url"> are swapped, then
 *     their parent <a> href is updated so external links open the right page.
 *
 * No full page reload is needed; a tiny session-sync fetch keeps the PHP
 * session in line so links navigated by the user open the chosen language.
 */
(function () {
  'use strict';

  const BASE = '/maxiworx';
  const CONTENT_API = BASE + '/cms/api/public-content.php';

  /* ---- Static UI-chrome translations (NEVER touch CMS content) ----
   * Supports {placeholders} via window.cmsT('key', { name: 'value' }). */
  const uiTranslations = {
    de: {
      // Nav
      'nav.studio':         'Studio',
      'nav.equipment':      'Equipment',
      'nav.sessions':       'Sessions & Rates',
      'nav.specials':       'Specials',
      'nav.references':     'Referenzen',
      'nav.book':           'Book Session',
      'nav.home':           'Home',
      'hero.scroll':        'Scroll',
      'contact.emailLabel': 'Deine E-Mail-Adresse',
      'contact.submit':     'Anfrage senden',
      'footer.imprint':     'Impressum',
      'footer.privacy':     'Datenschutz',
      'footer.terms':       'AGB',
      // Studio spec labels
      'studio.spec.area':         'Fläche',
      'studio.spec.ceiling':      'Deckenhöhe',
      'studio.spec.reverb':       'RT60',
      'studio.spec.isolation':    'Schalldämmung',
      // References — show-more / show-less toggle
      'artists.show_more':        '+ {count} weitere Künstler anzeigen',
      'artists.show_less':        '− Weniger anzeigen',
      'companies.show_more':      '+ {count} weitere Unternehmen anzeigen',
      'companies.show_less':      '− Weniger anzeigen',
      // Equipment — A/B compare player UI chrome
      'equipment.ab.compare':     'A/B Vergleich',
      'equipment.ab.loading':     'Buffering',
      'equipment.ab.level':       'Level',
      // Booking form
      'booking.project_name':     'Projektname / Bandname',
      'booking.genre':            'Genre',
      'booking.songs':            'Anzahl Songs / Tracks',
      'booking.duration':         'Gewünschter Zeitraum',
      'booking.date_from':        'Wunsch-Startdatum',
      'booking.date_to':          'Enddatum (optional)',
      'booking.description':      'Kurze Projektbeschreibung',
      'booking.firstname':        'Vorname',
      'booking.lastname':         'Nachname',
      'booking.email':            'E-Mail-Adresse',
      'booking.phone':            'Telefon (optional)',
      'booking.country':          'Land / Region',
      'booking.how':              'Wie hast du uns gefunden?',
      // Booking — select option texts
      'booking.choose':           'Bitte wählen',
      'booking.choose_optional':  'Bitte wählen (optional)',
      'booking.songs.1':          '1 Song / Single',
      'booking.songs.2_4':        '2–4 Songs',
      'booking.songs.5_8':        '5–8 Songs (EP)',
      'booking.songs.9plus':      '9+ Songs (Album)',
      'booking.songs.other':      'Sonstiges',
      'booking.duration.1day':    '1 Tag',
      'booking.duration.2_3day':  '2–3 Tage',
      'booking.duration.week':    '1 Woche',
      'booking.duration.flex':    'Flexibel',
      'booking.country.de':       'Deutschland',
      'booking.country.at':       'Österreich',
      'booking.country.ch':       'Schweiz',
      'booking.country.other':    'International',
      // Booking — availability finder + buttons + privacy
      'booking.avail.title':      'Freie Termine finden',
      'booking.avail.sub':        'Suche nach aufeinanderfolgenden freien Tagen im Studio-Kalender',
      'booking.avail.days':       'Tage',
      'booking.avail.search':     'Suchen',
      'booking.avail.selected':   '✓ Zeitfenster übernommen — Datum unten eingetragen.',
      'booking.tip_prefix':       'Tipp:',
      'booking.back':             'Zurück',
      'booking.next':             'Weiter',
      'booking.summary':          'Zusammenfassung',
      'booking.submit':           'Anfrage absenden',
      'booking.submitting':       'Wird gesendet…',
      // Booking summary (step 4) — JS-generated labels
      'booking.summary.service':  'Service',
      'booking.summary.project':  'Projekt',
      'booking.summary.tracks':   'Tracks',
      'booking.summary.dauer':    'Dauer',
      'booking.summary.start':    'Startdatum',
      'booking.summary.name':     'Name',
      'booking.summary.email':    'E-Mail',
      'booking.summary.empty':    '—',
      'booking.summary.flexible': 'Flexibel',
    },
    en: {
      'nav.studio':         'Studio',
      'nav.equipment':      'Equipment',
      'nav.sessions':       'Sessions & Rates',
      'nav.specials':       'Specials',
      'nav.references':     'References',
      'nav.book':           'Book Session',
      'nav.home':           'Home',
      'hero.scroll':        'Scroll',
      'contact.emailLabel': 'Your Email Address',
      'contact.submit':     'Send Inquiry',
      'footer.imprint':     'Imprint',
      'footer.privacy':     'Privacy Policy',
      'footer.terms':       'Terms',
      // Studio spec labels
      'studio.spec.area':         'Area',
      'studio.spec.ceiling':      'Ceiling Height',
      'studio.spec.reverb':       'RT60',
      'studio.spec.isolation':    'Sound Isolation',
      // References — show-more / show-less toggle
      'artists.show_more':        '+ Show {count} more artists',
      'artists.show_less':        '− Show less',
      'companies.show_more':      '+ Show {count} more companies',
      'companies.show_less':      '− Show less',
      // Equipment — A/B compare player UI chrome
      'equipment.ab.compare':     'A/B Compare',
      'equipment.ab.loading':     'Buffering',
      'equipment.ab.level':       'Level',
      // Booking form
      'booking.project_name':     'Project / Band Name',
      'booking.genre':            'Genre',
      'booking.songs':            'Number of Songs / Tracks',
      'booking.duration':         'Preferred Duration',
      'booking.date_from':        'Preferred Start Date',
      'booking.date_to':          'End Date (optional)',
      'booking.description':      'Short Project Description',
      'booking.firstname':        'First Name',
      'booking.lastname':         'Last Name',
      'booking.email':            'Email Address',
      'booking.phone':            'Phone (optional)',
      'booking.country':          'Country / Region',
      'booking.how':              'How did you find us?',
      // Booking — select option texts
      'booking.choose':           'Please choose',
      'booking.choose_optional':  'Please choose (optional)',
      'booking.songs.1':          '1 Song / Single',
      'booking.songs.2_4':        '2–4 Songs',
      'booking.songs.5_8':        '5–8 Songs (EP)',
      'booking.songs.9plus':      '9+ Songs (Album)',
      'booking.songs.other':      'Other',
      'booking.duration.1day':    '1 Day',
      'booking.duration.2_3day':  '2–3 Days',
      'booking.duration.week':    '1 Week',
      'booking.duration.flex':    'Flexible',
      'booking.country.de':       'Germany',
      'booking.country.at':       'Austria',
      'booking.country.ch':       'Switzerland',
      'booking.country.other':    'International',
      // Booking — availability finder + buttons + privacy
      'booking.avail.title':      'Find available dates',
      'booking.avail.sub':        'Search for consecutive free days in the studio calendar',
      'booking.avail.days':       'days',
      'booking.avail.search':     'Search',
      'booking.avail.selected':   '✓ Time window accepted — date filled in below.',
      'booking.tip_prefix':       'Tip:',
      'booking.back':             'Back',
      'booking.next':             'Next',
      'booking.summary':          'Summary',
      'booking.submit':           'Send request',
      'booking.submitting':       'Sending…',
      // Booking summary (step 4) — JS-generated labels
      'booking.summary.service':  'Service',
      'booking.summary.project':  'Project',
      'booking.summary.tracks':   'Tracks',
      'booking.summary.dauer':    'Duration',
      'booking.summary.start':    'Start date',
      'booking.summary.name':     'Name',
      'booking.summary.email':    'Email',
      'booking.summary.empty':    '—',
      'booking.summary.flexible': 'Flexible',
    }
  };

  /* ---- State ---- */
  let currentLang = (document.documentElement.lang || localStorage.getItem('mxw_lang') || 'de')
                      .toLowerCase().slice(0, 2);
  if (currentLang !== 'en') currentLang = 'de';

  // In-memory cache: { slug: { fieldKey: { de, en } } }
  const contentCache = {};

  /* ---- Helpers ---- */
  function getPageSlug() {
    // Match  /maxiworx/<slug>.php  →  <slug>
    const m = window.location.pathname.match(/\/([a-z0-9_\-]+)\.php(?:$|[?#])/i);
    if (m) return m[1].toLowerCase();
    // Trailing slash or root → index
    return 'index';
  }

  function loadPageContent(slug) {
    if (contentCache[slug]) return Promise.resolve(contentCache[slug]);
    return fetch(CONTENT_API + '?page=' + encodeURIComponent(slug), {
      method:      'GET',
      credentials: 'same-origin',
      cache:       'no-store'
    })
      .then(function (r) { return r.json(); })
      .then(function (j) {
        if (j && j.success && j.data) {
          contentCache[slug] = j.data;
          return j.data;
        }
        return {};
      })
      .catch(function () { return {}; });
  }

  /**
   * Lookup a UI string by key with optional {placeholder} substitution.
   * Exposed globally so page-local JS (e.g. references.php toggle button)
   * can read the active language strings without re-implementing the map.
   *
   * Example:  cmsT('artists.show_more', { count: 3 })
   *           → "+ 3 weitere Künstler anzeigen" / "+ Show 3 more artists"
   */
  function cmsT(key, args) {
    const t   = uiTranslations[currentLang] || uiTranslations.de;
    let   out = t[key];
    if (out === undefined) return key;            // fail open: show the key
    if (args && typeof args === 'object') {
      Object.keys(args).forEach(function (k) {
        out = out.replace(new RegExp('\\{' + k + '\\}', 'g'), String(args[k]));
      });
    }
    return out;
  }
  window.cmsT = cmsT;

  /* ---- DOM update routines ---- */
  function applyUiTranslations(lang) {
    const t = uiTranslations[lang] || uiTranslations.de;
    document.querySelectorAll('[data-i18n]').forEach(function (el) {
      if (el.hasAttribute('data-cms-key')) return;     // DB-content — leave to CMS swap
      const key = el.getAttribute('data-i18n');
      let   val = t[key];
      if (val === undefined) return;
      // Optional placeholder substitution via data-i18n-args='{"count":3}'
      const argsAttr = el.getAttribute('data-i18n-args');
      if (argsAttr) {
        try {
          const args = JSON.parse(argsAttr);
          Object.keys(args).forEach(function (k) {
            val = val.replace(new RegExp('\\{' + k + '\\}', 'g'), String(args[k]));
          });
        } catch (e) { /* invalid JSON — ignore */ }
      }
      el.innerHTML = val;
    });
  }

  /**
   * Escape HTML special chars, then restore a small whitelist of inline tags
   * that the CMS rich-text fields rely on (mirrors PHP cRaw behaviour for
   * <br>, <em>, <strong>, <i>, <b>). XSS-safe for arbitrary admin content.
   */
  function renderRichText(text) {
    const escaped = String(text)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
    return escaped
      .replace(/&lt;br\s*\/?&gt;/gi, '<br>')
      .replace(/&lt;(\/?)(em|strong|i|b)&gt;/gi, '<$1$2>');
  }

  function applyCmsContent(content, lang) {
    if (!content) return;
    document.querySelectorAll('[data-cms-key]').forEach(function (el) {
      const key   = el.getAttribute('data-cms-key');
      const entry = content[key];
      if (!entry) return;
      const val = entry[lang] || entry.de || '';
      if (val === '') return; // keep the existing PHP-rendered fallback text
      // Use innerHTML with whitelist escaping so inline tags like <br>
      // (used by *.cta titles) render correctly while blocking XSS.
      el.innerHTML = renderRichText(val);
    });

    // Any *.url placeholder → update closest <a> href so external links
    // (Spotify banner, video buttons, artist links) open the right page.
    document.querySelectorAll('[data-cms-key$=".url"]').forEach(function (el) {
      const url = (el.textContent || '').trim();
      if (!url) return;
      const a = el.closest('a[href]');
      if (a) a.href = url;
    });
  }

  /**
   * Server-rendered content that lives in its own DB tables (cms_artists,
   * cms_companies, …) is NOT in cms_content, so the public-content API
   * doesn't know about it. To still support live-switching, those pages
   * embed BOTH language values in data-de / data-en attributes during
   * PHP render. This swap picks the right one at click time.
   *
   * Convention:
   *   <span data-de="DE text" data-en="EN text">DE text</span>
   * If only one of the two attributes is present, the element is skipped.
   */
  function applyDualLangText(lang) {
    document.querySelectorAll('[data-de][data-en]').forEach(function (el) {
      const deVal = el.getAttribute('data-de');
      const enVal = el.getAttribute('data-en');
      el.textContent = (lang === 'en') ? enVal : deVal;
    });
  }

  function applyActiveStates(lang) {
    // Highlight the chosen language button in both desktop and mobile menus
    document.querySelectorAll(
      '.settings-opt--lang, .mobile-settings-opt--lang, ' +
      '.lang-option, .mobile-lang-btn'
    ).forEach(function (opt) {
      const optLang = opt.dataset && opt.dataset.lang;
      if (optLang) opt.classList.toggle('active', optLang === lang);
    });
  }

  function updateCaption() {
    const activeSlide = document.querySelector('.slide.active');
    const captionEl   = document.getElementById('slide-caption');
    if (!activeSlide || !captionEl) return;
    const caption = activeSlide.getAttribute('data-caption-' + currentLang)
                 || activeSlide.getAttribute('data-caption-de')
                 || '';
    captionEl.style.opacity = '0';
    setTimeout(function () {
      captionEl.textContent = caption;
      captionEl.style.opacity = '1';
    }, 200);
  }
  window.updateSlideCaptionI18n = updateCaption;

  /* ---- Main entry: switch language live (no reload) ---- */
  function setLang(lang, opts) {
    opts = opts || {};
    if (lang !== 'de' && lang !== 'en') lang = 'de';

    currentLang = lang;
    localStorage.setItem('mxw_lang', lang);
    document.documentElement.lang = lang;

    applyUiTranslations(lang);
    applyDualLangText(lang);
    applyActiveStates(lang);
    updateCaption();

    // Pull CMS content from cache or API and swap text/URLs
    const slug = getPageSlug();
    loadPageContent(slug).then(function (content) {
      applyCmsContent(content, lang);
      // Re-run slide caption after potential DOM updates
      updateCaption();
    });

    // Keep the PHP session in sync (best-effort, no waiting). This makes
    // subsequent full-page navigation (clicking a nav link) open the right
    // language even if the browser drops fetch state.
    if (!opts.skipSessionSync) {
      try {
        fetch(BASE + '/?lang=' + encodeURIComponent(lang), {
          method:      'GET',
          credentials: 'same-origin',
          cache:       'no-store',
          keepalive:   true
        });
      } catch (e) { /* ignore */ }
    }
  }
  window.maxiworxSetLang = setLang;

  /* ---- Click bindings (Desktop + Mobile + Home-only flag switcher) ---- */
  function bindLangClicks() {
    const selectors = [
      '.settings-opt--lang',     // shared nav.php (desktop)
      '.mobile-settings-opt--lang', // shared nav.php (mobile)
      '.lang-option',            // legacy homepage dropdown
      '.mobile-lang-btn'         // legacy homepage mobile
    ].join(', ');

    document.querySelectorAll(selectors).forEach(function (opt) {
      if (opt.dataset.langBound === '1') return;
      opt.dataset.langBound = '1';
      opt.addEventListener('click', function (e) {
        e.stopPropagation();
        const lang = this.dataset.lang;
        if (!lang || lang === currentLang) return;
        setLang(lang);
      });
    });
  }

  /* ---- Init: apply current language, pre-fetch content cache ---- */
  function init() {
    // Capture localStorage value BEFORE we touch it, so we can detect mismatch
    const stored = (localStorage.getItem('mxw_lang') || '').toLowerCase().slice(0, 2);
    const renderedLang = currentLang;

    document.documentElement.lang = renderedLang;
    applyUiTranslations(renderedLang);
    applyDualLangText(renderedLang);
    applyActiveStates(renderedLang);
    bindLangClicks();
    updateCaption();

    // Pre-fetch this page's content so the FIRST click is instant
    loadPageContent(getPageSlug());

    // If localStorage previously had a different language (session expired,
    // private window, etc.) → live-switch to the user's preference now.
    if ((stored === 'de' || stored === 'en') && stored !== renderedLang) {
      setLang(stored);
    } else {
      // Persist the rendered language as the new baseline
      localStorage.setItem('mxw_lang', renderedLang);
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
